#!/usr/bin/env bash

BRAVE_DIR="$HOME/.config/BraveSoftware/Brave-Browser/Default"
REPO_DIR="$(dirname "$0")"

backup() {
    cp "$BRAVE_DIR/Bookmarks" "$REPO_DIR/Bookmarks"
    cp "$BRAVE_DIR/Preferences" "$REPO_DIR/Preferences"
    echo "Backed up Bookmarks and Preferences"
    cd "$REPO_DIR" && git add Bookmarks Preferences && git commit -m "brave: update bookmarks and preferences" && git push
}

restore() {
    cp "$REPO_DIR/Bookmarks" "$BRAVE_DIR/Bookmarks"
    cp "$REPO_DIR/Preferences" "$BRAVE_DIR/Preferences"
    echo "Restored Bookmarks and Preferences"
}

case "$1" in
    backup)  backup ;;
    restore) restore ;;
    *) echo "Usage: $0 [backup|restore]" ;;
esac

